async def add_category_products():
    """Add category-specific products with real images"""
    products_collection = db.products
    
    print("📦 Adding category-specific products with real images...\n")
    await products_collection.delete_many({})
    print("✅ Cleared old products\n")
    
    total_added = 0
    for category, products in PRODUCTS_BY_CATEGORY.items():
        print(f"📂 Category: {category}")
        for product in products:
            product["id"] = str(uuid.uuid4())
            product["created_at"] = datetime.now(timezone.utc)
            product["seller_id"] = "system"
            product["clicks"] = 0
            product["sales"] = 0
            product["featured"] = total_added < 5  # Feature first 5 products
            
            await products_collection.insert_one(product)
            total_added += 1
            print(f"   ✅ {product['title']} (${product['price']} - {product['subcategory']})")
        print()
    
    count = await products_collection.count_documents({})
    print(f"\n✅ Total products added: {count}")
    
    # Show category breakdown
    tech_count = await products_collection.count_documents({"category": "Tech"})
    fashion_count = await products_collection.count_documents({"category": "Fashion"})
    fitness_count = await products_collection.count_documents({"category": "Fitness"})
    home_count = await products_collection.count_documents({"category": "Home"})
    ai_count = await products_collection.count_documents({"category": "AI Tools"})
    hustle_count = await products_collection.count_documents({"category": "Side Hustles"})
    
    print("\n📊 Category Breakdown:")
    print(f"   Tech: {tech_count} products")
    print(f"   Fashion: {fashion_count} products")
    print(f"   Fitness: {fitness_count} products")
    print(f"   Home: {home_count} products")
    print(f"   AI Tools: {ai_count} products")
    print(f"   Side Hustles: {hustle_count} products")


async def main():
    try:
        await add_category_products()
        print("\n✅ All products added with:")
        print("   ✓ Category-specific items")
        print("   ✓ Real product images")
        print("   ✓ Accurate prices")
    except Exception as e:
        print(f"❌ Error: {e}")
    finally:
        client.close()


if __name__ == "__main__":
    asyncio.run(main())
